script:
frappe.ui.form.on('Prospect', {
    refresh: function(frm) {
        if (!frm.doc.__islocal) {
            frm.add_custom_button(__('Create Lead'), function () {
                frappe.call({
                    method: "frappe.client.get_list",
                    args: {
                        doctype: "Lead",
                        filters: {
                            prospect: frm.doc.name
                        },
                        fields: ["name"]
                    },
                    callback: function (res) {
                        if (res.message && res.message.length > 0) {
                            frappe.msgprint("Lead already exists: <b>" + res.message[0].name + "</b>");
                            frappe.set_route("Form", "Lead", res.message[0].name);
                        } else {
                            // No lead exists, so create one
                            frappe.call({
                                method: "frappe.client.insert",
                                args: {
                                    doc: {
                                        doctype: "Lead",
                                        lead_name: frm.doc.full_name || frm.doc.company_name || frm.doc.name,
                                        prospect: frm.doc.name,
                                        full_name: frm.doc.full_name,
                                        email: frm.doc.email,
                                        phone: frm.doc.phone,
                                        company_name: frm.doc.company_name,
                                        industry: frm.doc.industry,
                                        region: frm.doc.region,
                                        status: "Open",
                                        source: frm.doc.source,
                                        notes: frm.doc.notes
                                    }
                                },
                                callback: function (r) {
                                    if (!r.exc) {
                                        frappe.msgprint(__('Lead Created Successfully'));
                                        frappe.set_route("Form", "Lead", r.message.name);
                                    }
                                }
                            });
                        }
                    }
                });
            });
        }
    }
});

